q=A.a(["128th Constitutional Amendment \u2014 33% women reservation in Lok Sabha & state assemblies","Sub-reservation for SC and ST women within the quota","Effective only after next Census + delimitation exercise","Valid for 15 years, extendable by Parliament","First introduced in 1996 \u2014 took 27 years to pass"],b8)
